// Friendly aliases for alternate spellings used in the app.
const ALIASES: Record<string, string> = {
  "mahendra singh dhoni": "ms dhoni",
  "lokesh rahul": "kl rahul",
  "thangarasu natarajan": "t natarajan",
  "vaibhav suryavanshi": "vaibhav sooryavanshi",
  "muttiah muralitharan": "muthiah muralidaran",
  "b sai sudharsan": "sai sudharsan",
};

const normalize = (name: string) => name.toLowerCase().trim();

/**
 * Returns a real player photo URL (Wikimedia) or undefined if we don't have one.
 * Callers (e.g. playerDatabase.ts) fall back to a generated initials avatar.
 */
export const getPlayerCricinfoImage = (name: string): string | undefined => {
  if (!name) return undefined;
  const key = normalize(name);
  return PLAYER_IMAGES[key] ?? PLAYER_IMAGES[ALIASES[key] ?? ""];
};

/** Convenience helper that always returns a URL. */
export const getPlayerImageOrFallback = (name: string): string => {
  return (
    getPlayerCricinfoImage(name) ??
    `https://api.dicebear.com/7.x/initials/svg?seed=${encodeURIComponent(name)}&backgroundColor=4f46e5,7c3aed,db2777&textColor=ffffff`
  );
};

export const PLAYER_IMAGE_FALLBACK =
  "https://api.dicebear.com/7.x/initials/svg?seed=Cricketer&backgroundColor=4f46e5";
